{
  "messages": [
    {
      "destination": "{{test_destination}}",
      "callback_data": "moe_text_{{$timestamp}}",
      "fallback_order": ["RCS", "SMS"],
      "rcs": {
        "bot_id": "{{bot_id}}",
        "template_id": "test15",
        "message_content": {
          "type": "TEXT",
          "data": {
            "text": "Hello John!",
            "parameters": { "name": "John", "company": "MoEngage" }
          }
        }
      },
      "sms": {
        "sender": "{{sms_sender}}",
        "message": "Thanks for sharing your documents with Smartping. Our team is reviewing them as part of the verification process. We’ll notify you once it’s complete or if any more details are needed. For support, reach us at gracee– Smartping",
        "template_id": "{{sms_template_id}}"
      }
    }
  ]
}

